// +δ bias on green-list logits, then argmax of the biased distribution
let mut watermark = WatermarkState::new(GAMMA, DELTA);
let mut pending = vec![first_token];

for _ in 0..max_tokens {
    let mut pass = ctx.forward();
    pass.input(&pending);
    let last_idx = (pending.len() - 1) as u32;

    // Read the model's natural softmax (k=0 → full vocab).
    let h = pass.probe(last_idx, Distribution { temperature: 1.0, k: 0 });
    let out = pass.execute().await?;
    let (ids, probs) = out.distribution(h).unwrap();

    // In-WASM hash → green list → +δ bias → argmax.
    let chosen = watermark.sample_biased(ids, probs);
    pending = vec![chosen];
}
